--
-- Структура таблицы `articles`
--

CREATE TABLE `articles` (
  `id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) DEFAULT NULL,
  `abstract` text NOT NULL,
  `content` longtext NOT NULL,
  `authors` json NOT NULL,
  `publication_date` date NOT NULL,
  `journal_name` varchar(255) DEFAULT NULL,
  `volume` varchar(50) DEFAULT NULL,
  `issue` varchar(50) DEFAULT NULL,
  `pages` varchar(50) DEFAULT NULL,
  `views_count` int DEFAULT '0',
  `status` enum('published','draft','under_review') DEFAULT 'draft',
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Дамп данных таблицы `articles`
--

INSERT INTO `articles` (`id`, `title`, `slug`, `abstract`, `content`, `authors`, `publication_date`, `journal_name`, `volume`, `issue`, `pages`, `views_count`, `status`, `created_by`, `created_at`) VALUES
(1, 'Разработка системы технического зрения для робота-лаборанта', 'vision-lab-assistant', 'Представлена архитектура системы компьютерного зрения для мобильного робота \"Лаборант-ассистент\". Рассмотрены методы распознавания лабораторной посуды и навигации в условиях лаборатории.', 'Разработан прототип системы технического зрения на базе OpenCV и YOLOv8. Проведены испытания по распознаванию пробирок и реактивов. Точность распознавания составила 95% в условиях лабораторного освещения. Планируется интеграция с ROS2.', '[1, 2]', '2025-01-15', 'Вестник робототехники', '12', '1', '45-52', 156, 'published', 1, '2026-02-16 08:00:00'),
(2, 'Нейросетевая сортировка отходов для автономного робота', 'waste-sorting-robot', 'Исследование методов классификации мусора (пластик, бумага, стекло) с помощью сверточных нейросетей для робота-мусоросборщика. Сравнение архитектур MobileNet и ResNet.', 'Проведено обучение нейросети на датасете из 5000 изображений. Лучший результат показала MobileNetV2 с точностью 89%. Реализован прототип на Raspberry Pi с камерой. Работа поддержана грантом университета.', '[2, 3]', '2025-02-10', 'Информационные технологии', '8', '2', '23-30', 95, 'published', 2, '2026-02-16 08:05:00'),
(3, 'Управление складским роботом для инвентаризации библиотечных фондов', 'warehouse-robot-inventory', 'Представлен алгоритм навигации и идентификации книг для компактного складского робота. Использованы RFID-метки и техническое зрение для поиска объектов на стеллажах.', 'Разработан прототип робота на колесной базе с манипулятором. Проведено тестирование в учебной библиотеке. Точность инвентаризации - 94%. Время автономной работы - 3 часа.', '[1, 4]', '2025-03-05', 'Мехатроника и робототехника', '5', '3', '67-74', 67, 'under_review', 3, '2026-02-16 08:10:00'),
(4, 'Агробот: автоматизация полива и мониторинга растений в теплицах', 'agrobot-plant-care', 'Разработка мобильной платформы для автоматического полива и мониторинга состояния растений. Система собирает данные о влажности почвы, освещенности и температуре.', 'Создан прототип агробота на базе Arduino с датчиками влажности. Реализована система автополива по расписанию. Интерфейс управления через веб-приложение. Проведены испытания на 10 растениях в течение месяца.', '[3, 5]', '2025-03-20', 'Агроинженерия', '14', '2', '112-119', 48, 'published', 4, '2026-02-16 08:15:00'),
(5, 'Применение ROS2 в образовательных робототехнических проектах', 'ros2-education-projects', 'Опыт внедрения ROS2 в учебный процесс при разработке роботизированных систем. Рассмотрены типовые архитектуры и шаблоны для быстрого прототипирования.', 'Представлены методические материалы и примеры кода для создания простых роботов на ROS2. Описана структура пакетов, ноды и топики. Курс апробирован на 30 студентах.', '[1, 2, 3]', '2025-04-01', 'Образовательные технологии', '9', '1', '34-41', 112, 'published', 5, '2026-02-16 08:20:00'),
(6, 'Черновик: Перспективы развития роботов-помощников для научных лабораторий', 'lab-assistants-draft', 'Аналитический обзор современных тенденций в разработке лабораторных роботов. Наброски к будущей статье.', 'Планируется рассмотреть: существующие коммерческие решения, open-source альтернативы, требования безопасности, интеграцию с лабораторным оборудованием. Статья в процессе написания.', '[1]', '2025-04-10', NULL, NULL, NULL, NULL, 0, 'draft', 1, '2026-02-16 08:25:00');

