CREATE TABLE `blog_posts` (
  `id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `excerpt` text NOT NULL,
  `content` longtext NOT NULL,
  `author_id` int NOT NULL,
  `featured_image_url` varchar(255) DEFAULT NULL,
  `tags` json DEFAULT NULL,
  `views_count` int DEFAULT '0',
  `comments_enabled` tinyint(1) DEFAULT '1',
  `status` enum('published','draft') DEFAULT 'draft',
  `published_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Дамп данных таблицы `blog_posts`
--

INSERT INTO `blog_posts` (`id`, `title`, `slug`, `excerpt`, `content`, `author_id`, `featured_image_url`, `tags`, `views_count`, `comments_enabled`, `status`, `published_at`, `created_at`, `updated_at`) VALUES
(1, 'Как мы собрали первого робота-лаборанта за выходные', 'kak-my-sobrali-robota-labiranta', 'Рассказ о том, как команда за 48 часов создала прототип мобильного робота для перевозки пробирок. Хакатон, кофе и немного магии.', 'Начало\n\nВ прошлую пятницу вечером мы решили: а почему бы не попробовать собрать рабочего робота за выходные? Вооружились Raspberry Pi, старыми моторами от игрушечной машинки и энтузиазмом.\n\nДень 1: Сборка шасси\n\nСобрали раму из алюминиевого профиля, прикрутили колеса. Драйверы моторов подключили к пинам GPIO. В 3 часа ночи робот впервые поехал!\n\nПервый выезд\n\nДень 2: Компьютерное зрение\n\nНаучили робота видеть пробирки с помощью OpenCV. Использовали цветовые фильтры для выделения красных крышек. К вечеру робот уверенно отличал пробирки от всего остального.\n\nИтоги\n\nПолучился полноценный прототип, который теперь живет в лаборатории и помогает аспирантам таскать образцы. Конечно, до идеала далеко, но главное - мы доказали, что можно быстро стартовать.', 1, '/uploads/blog/lab-assitant-prototype.jpg', '[\"хакатон\", \"прототип\", \"лаборант-ассистент\", \"Raspberry Pi\"]', 342, 1, 'published', '2025-03-01 07:00:00', '2025-03-01 05:00:00', '2025-03-02 12:30:00'),
(2, 'Полевые испытания робота-мусоросборщика в парке', 'polevye-ispytaniya-musorosborschika', 'Как мы выгуливали робота в городском парке и что из этого вышло. Забавные моменты, неожиданные препятствия и статистика собранного мусора.', 'Подготовка\n\nВ субботу утром погода порадовала солнцем. Мы взяли робота, ноутбук, запасные батареи и отправились в парк им. Горького. Задача: проверить работу в реальных условиях.\n\nЧто пошло не по плану\n\nГолуби оказались главными врагами робота. Они принимали его за хищника и пытались атаковать. Пришлось добавить в программу замедление при виде птиц.\n\nДети тоже проявили активный интерес. Двое мальчишек бежали за роботом полчаса и помогали собирать мусор в мешок. Будущие коллеги, надеемся!\n\nРезультаты\n\nПластиковые бутылки: 37 штук\nБумажные стаканчики: 24 штуки\nСтекло: 8 бутылок\nНеопознанные объекты: 5 (один оказался потерянным носком)\n\nСистема сортировки сработала на 87% точности. Будем дообучать нейросеть.', 2, '/uploads/blog/robot-park-test.jpg', '[\"полевые испытания\", \"мусоросборщик\", \"парк\", \"экология\"]', 216, 1, 'published', '2025-03-15 11:30:00', '2025-03-14 15:20:00', '2026-02-16 17:20:48'),
(3, 'Как мы оцифровали библиотеку с помощью робота за 2 дня', 'robot-inventarizaciya-biblioteki', 'Эксперимент: можно ли за выходные провести полную инвентаризацию книжного фонда силами одного робота и двух программистов?', 'Задача\n\nВ нашей университетской библиотеке 15 тысяч книг. Ручная инвентаризация занимает неделю. Мы решили проверить, справится ли наш складской робот быстрее.\n\nРешение\n\nУстановили на робота RFID-считыватель и камеру. Робот проезжал вдоль стеллажей, считывал метки и фотографировал корешки книг. Данные сразу загружались в базу.\n\nПсевдокод алгоритма\nwhile(books_left) {\n    move_along_shelf();\n    scan_rfid();\n    take_photo();\n    if (book_not_found) alert_librarian();\n}\n\nИтоги\n\nЗа 14 часов робот обработал все стеллажи. Найдено 237 книг, которые числились утерянными (они просто стояли не на своих местах). Библиотекари счастливы, робот получил почетную грамоту.', 3, '/uploads/blog/library-robot.jpg', '[\"библиотека\", \"инвентаризация\", \"RFID\", \"складской робот\"]', 178, 1, 'published', '2025-03-22 08:15:00', '2025-03-20 13:40:00', '2025-03-23 05:30:00'),
(4, 'Агробот против засухи: спасаем комнатные растения', 'agrobot-protiv-zasuhi', 'Пока хозяева в отпуске, робот заботится о цветах. Первый опыт автоматического полива и мониторинга в обычной квартире.', 'Предыстория\n\nНаш коллега уехал в отпуск на две недели и попросил присмотреть за растениями. Мы решили не просто поливать, а использовать нашего агробота в реальных домашних условиях.\n\nОснащение\n\nРобот получил датчики влажности почвы (по одному на каждый крупный горшок), резервуар с водой на 5 литров и систему капельного полива.\n\nХронология событий\n\nДень 1-3: Робот исправно измеряет влажность, поливает фикус каждые 2 дня.\n\nДень 4: Кот хозяина пытается охотиться на робота. Робот уворачивается. Добавляем алгоритм избегания кошек.\n\nДень 7: Заканчивается вода. Робот отправляет SMS хозяину. Соседка приходит на помощь.\n\nДень 14: Хозяин возвращается. Все растения живы. Кот в обиде на робота.\n\nВыводы\n\nАгробот успешно справился с миссией. В следующей версии добавим подогрев воды для тропических растений.', 4, '/uploads/blog/agrobot-home.jpg', '[\"агробот\", \"растения\", \"полив\", \"домашняя автоматизация\"]', 421, 1, 'published', '2025-04-01 06:20:00', '2025-03-30 09:10:00', '2025-04-02 15:00:00'),
(5, 'Почему мы перешли на ROS2 и вам советуем', 'perehod-na-ros2', 'Технический пост о миграции с ROS1 на ROS2. Сравнение производительности, подводные камни и примеры кода.', 'Предыстория\n\nДолгое время наши проекты базировались на ROS1. Но с выходом новых версий Ubuntu поддержка ROS1 становится проблематичной. Решили переезжать.\n\nЧто изменилось\n\nСамый большой сюрприз - система сборки. colcon вместо catkin. Пришлось переписывать CMakeLists.txt для всех пакетов.\n\nТопики теперь типизированы строже. Если раньше можно было отправить не тот тип сообщения и получить предупреждение, то теперь - ошибка компиляции.\n\nСравнение производительности\n\nЗамерили latency при передаче изображений с камеры:\nROS1: в среднем 45 мс\nROS2: в среднем 28 мс (приоритетные QoS настройки)\n\nСоветы новичкам\n\n1. Не пытайтесь мигрировать все сразу - оставьте мосты между ROS1 и ROS2\n2. Изучите концепцию QoS - это мощный инструмент\n3. Будьте готовы к тому, что не все пакеты портированы\n\nВ целом, переход оправдан. Код стал чище, система стабильнее.', 1, '/uploads/blog/ros2-migration.jpg', '[\"ROS2\", \"ROS1\", \"программирование\", \"туториал\"]', 568, 1, 'published', '2025-04-10 13:45:00', '2025-04-08 06:30:00', '2026-02-16 17:46:32'),
(6, 'Черновик: Интервью с руководителем Центра роботизированных решений', 'intervyu-s-rukovoditelem', 'Планируем взять интервью у научного руководителя о планах развития, трудностях и победах. Черновик вопросов.', 'Вопросы для интервью:\n\n1. Как возникла идея создать Центр роботизированных решений?\n2. Какие проекты сейчас в приоритете?\n3. С какими техническими трудностями столкнулись при разработке робота-лаборанта?\n4. Есть ли планы по коммерциализации разработок?\n5. Что посоветуете студентам, которые хотят заниматься робототехникой?\n6. Какой проект считаете самым удачным?\n7. Куда движется робототехника в ближайшие 5 лет?\n\nСтатья в разработке. Дата публикации: ориентировочно май 2025', 5, NULL, '[\"интервью\", \"планы\", \"черновик\"]', 0, 1, 'draft', NULL, '2025-04-15 10:20:00', '2025-04-15 10:20:00'),
(7, 'Наш опыт участия в хакатоне \"Роботы для жизни\"', 'hackathon-robots-for-life', 'Рассказ о том, как наша команда заняла второе место с проектом робота-помощника для пожилых людей.', 'Формат хакатона\n\n48 часов, 20 команд, тема: роботы для социальной сферы. Мы решили сделать простого робота, который может принести лекарства, воду или вызвать помощь.\n\nПроцесс\n\nПервые 6 часов ушли на концепцию. Решили использовать готовую платформу Roomba как базу, сверху установили планшет для общения, манипулятор из LEGO и корзинку для предметов.\n\nНочью программировали систему распознавания голосовых команд. Использовали Vosk API - работает офлайн, что важно для дома.\n\nДемо\n\nПоказали сценку: \"бабушка\" просит принести таблетки. Робот едет к тумбочке, распознает нужную коробочку по цвету, захватывает и везет. Зал аплодировал.\n\nРезультат\n\n2 место и приз зрительских симпатий. И главное - договоренность с центром социального обслуживания о тестировании в реальных условиях.', 2, '/uploads/blog/hackathon-win.jpg', '[\"хакатон\", \"победа\", \"социальные проекты\", \"события\"]', 299, 1, 'published', '2025-04-05 17:30:00', '2025-04-03 08:45:00', '2026-02-16 17:46:53'),
(8, 'Обзор библиотек компьютерного зрения для Raspberry Pi', 'computer-vision-libraries-raspberry', 'Сравнение OpenCV, TensorFlow Lite и PyTorch Mobile на Raspberry Pi 4. Скорость работы, точность, потребление памяти.', 'Зачем это нужно\n\nНа всех наших роботах стоит Raspberry Pi. Важно выбрать оптимальный стек для задач компьютерного зрения.\n\nТестовый стенд\n\nRaspberry Pi 4 4GB, камера Raspberry Pi Camera v2, задача: распознавание объектов (пробирки, мусор, книги).\n\nРезультаты\n\nOpenCV с HOG + SVM\nСкорость: 15 FPS\nТочность: 78%\nПамять: 120 MB\nПлюсы: легко настраивать, не требует обучения\n\nTensorFlow Lite (MobileNetV2)\nСкорость: 8 FPS\nТочность: 91%\nПамять: 180 MB\nПлюсы: высокая точность\n\nPyTorch Mobile (ResNet18)\nСкорость: 3 FPS\nТочность: 93%\nПамять: 320 MB\nМинусы: медленно, много памяти\n\nНаш выбор\n\nИспользуем TensorFlow Lite как золотую середину. Для простых задач - OpenCV, для сложных - дообучаем MobileNet.', 3, '/uploads/blog/cv-comparison.jpg', '[\"компьютерное зрение\", \"Raspberry Pi\", \"OpenCV\", \"TensorFlow\", \"сравнение\"]', 190, 1, 'published', '2025-03-18 09:00:00', '2025-03-16 11:30:00', '2026-02-16 17:20:52'),
(9, 'Как мы сделали умную теплицу на Arduino за 5000 рублей', 'smart-greenhouse-arduino', 'Бюджетный проект автоматизированной теплицы для балкона. Своими руками, без пайки и сложного программирования.', 'Идея\n\nВыращивать зелень на балконе, но не хватает времени поливать и следить. Решили автоматизировать.\n\nКомпоненты\n\nArduino Uno - 500 руб\nДатчик влажности почвы - 150 руб\nДатчик температуры и влажности DHT22 - 300 руб\nРеле для управления насосом - 200 руб\nПомпа с трубками - 400 руб\nСветодиодная лента для подсветки - 500 руб\nLCD экран для вывода информации - 400 руб\nПровода, соединители, корпус - 1000 руб\n\nИтого: ~3450 руб (с запасом)\n\nКод\n\nvoid loop() {\n  int moisture = analogRead(moisturePin);\n  if (moisture < DRY_THRESHOLD) {\n    digitalWrite(pumpPin, HIGH);\n    delay(3000);\n    digitalWrite(pumpPin, LOW);\n  }\n  delay(60000); // проверка раз в минуту\n}\n\nРезультат\n\nУкроп растет как на дрожжах. Базилик счастлив. Помидоры завязываются. Проект забрала домой мама одного из разработчиков.', 4, '/uploads/blog/smart-greenhouse.jpg', '[\"Arduino\", \"теплица\", \"DIY\", \"автоматизация\", \"бюджетный проект\"]', 523, 1, 'published', '2025-02-20 08:30:00', '2025-02-18 06:15:00', '2025-02-21 13:40:00'),
(10, 'План развития Центра на 2025-2026 год', 'plan-razvitiya-2025-2026', 'Официальный пост о планах: новые проекты, гранты, публикации и партнерства.', 'Текущее состояние\n\nЗа 2024 год мы реализовали 4 прототипа, опубликовали 3 статьи, выиграли 2 гранта. Команда выросла до 7 постоянных участников.\n\nПланы на 2025\n\nQ2: Завершение испытаний робота-лаборанта в химической лаборатории\nQ3: Участие в международной конференции по робототехнике\nQ4: Запуск серии мастер-классов для школьников по робототехнике\n\nНовые проекты\n\n1. Робот-курьер для корпусов университета\n2. Система автоматического кормления животных для приюта\n3. Образовательный конструктор для обучения нейросетям\n\nПартнерства\n\nВедем переговоры с кафедрой биологии о совместных проектах по агроботам. Также планируем сотрудничать с местным технопарком.\n\nПриглашаем всех заинтересованных студентов и разработчиков присоединяться!', 5, '/uploads/blog/development-plan.jpg', '[\"планы\", \"развитие\", \"команда\", \"новости\", \"2025\"]', 146, 1, 'published', '2025-04-12 06:00:00', '2025-04-10 12:30:00', '2026-02-16 17:47:17');

