--
-- Структура таблицы `datasets`
--

CREATE TABLE `datasets` (
  `id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text NOT NULL,
  `access_level` enum('public','restricted','private') DEFAULT 'restricted',
  `related_project_id` int DEFAULT NULL,
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Дамп данных таблицы `datasets`
--

INSERT INTO `datasets` (`id`, `title`, `description`, `access_level`, `related_project_id`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'Датасет изображений лабораторной посуды для обучения систем компьютерного зрения', 'Коллекция из 5000 размеченных изображений пробирок, колб, чашек Петри и другого лабораторного оборудования. Снимки сделаны при разном освещении и ракурсах для обучения робота-лаборанта. Формат: JPG, разметка в COCO JSON.', 'public', 1, 1, '2025-01-10 07:00:00', '2025-01-10 07:00:00'),
(2, 'Датасет отходов для робота-мусоросборщика', 'Более 3000 изображений мусора (пластиковые бутылки, бумажные стаканы, стеклянные банки, алюминиевые банки) на различных фонах: асфальт, трава, песок. Разметка категорий и bounding boxes. Использовался для обучения нейросети сортировки.', 'public', 2, 2, '2025-01-15 11:30:00', '2025-01-15 11:30:00'),
(3, 'RFID-метки библиотечных книг', 'База данных RFID-меток 15000 книг из университетской библиотеки с привязкой к разделам и стеллажам. Данные использовались для навигации складского робота и инвентаризации.', 'restricted', 3, 3, '2025-02-01 06:15:00', '2025-02-01 06:15:00'),
(4, 'Показатели влажности почвы для агробота', 'Логи датчиков влажности почвы с 10 различных растений за период 3 месяца. Частота измерений: каждые 15 минут. Включает данные о поливе и реакции растений. Полевые испытания в квартире и теплице.', 'public', 4, 4, '2025-02-20 08:45:00', '2025-02-20 08:45:00'),
(5, 'Траектории движения роботов в лабораторных условиях', 'Записи траекторий движения роботов (лаборант, мусоросборщик, складской) в различных сценариях. Формат: CSV с координатами x, y, углом поворота, временной меткой. Всего 500 записей.', 'restricted', 1, 2, '2025-03-05 13:20:00', '2025-03-05 13:20:00'),
(6, 'Звуковые команды для управления роботом', 'Набор голосовых команд на русском языке для управления роботами: \"подъедь\", \"стоп\", \"принеси\", \"ищи\", \"поливай\". 50 дикторов, 10 повторений каждой команды. Формат: WAV, 16kHz.', 'public', NULL, 5, '2025-03-12 10:10:00', '2025-03-12 10:10:00'),
(7, 'Данные с лидара для построения карт помещений', 'Сырые данные с лидара робота-лаборанта при движении по лаборатории и коридорам. Может использоваться для обучения SLAM-алгоритмов. Формат: ROS bags.', 'private', 1, 1, '2025-03-18 05:30:00', '2025-03-18 05:30:00');

