--
-- Структура таблицы `projects`
--

CREATE TABLE `projects` (
  `id` int NOT NULL,
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `short_description` text NOT NULL,
  `full_description` longtext NOT NULL,
  `objectives` json NOT NULL,
  `methodologies` json DEFAULT NULL,
  `start_date` date NOT NULL,
  `end_date` date DEFAULT NULL,
  `current_status` enum('active','completed','planned','on_hold') DEFAULT 'planned',
  `funding_source` varchar(255) DEFAULT NULL,
  `budget` decimal(15,2) DEFAULT NULL,
  `team_members` json DEFAULT NULL,
  `results` text,
  `featured_image_url` varchar(255) DEFAULT NULL,
  `gallery` json DEFAULT NULL,
  `status` enum('published','draft') DEFAULT 'draft',
  `created_by` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

--
-- Дамп данных таблицы `projects`
--

INSERT INTO `projects` (`id`, `title`, `slug`, `short_description`, `full_description`, `objectives`, `methodologies`, `start_date`, `end_date`, `current_status`, `funding_source`, `budget`, `team_members`, `results`, `featured_image_url`, `gallery`, `status`, `created_by`, `created_at`, `updated_at`) VALUES
(1, 'Лаборант-ассистент: мобильный робот для автономной перевозки образцов', 'lab-assistant-robot', 'Разработка мобильного робота для автоматизации рутинных задач в научных лабораториях: перевозка пробирок, реактивов и образцов между стеллажами и рабочими местами.', 'Проект \"Лаборант-ассистент\" представляет собой комплексную разработку автономного мобильного робота, предназначенного для автоматизации рутинных операций в научных и медицинских лабораториях. Идея проекта возникла после наблюдения за работой лаборантов химического факультета, которые тратят до 30% рабочего времени на перемещение пробирок, реактивов и образцов между различными точками лаборатории.\n\nТехническая архитектура робота построена на базе ROS2 (Robot Operating System 2), что обеспечивает модульность и масштабируемость системы. Аппаратная платформа включает следующие ключевые компоненты:\n\n1. Шасси: четырехколесная платформа с независимым приводом каждого колеса (механизм поворота типа \"танковый разворот\"). Размеры 50x40x30 см, дорожный просвет 5 см. Материал корпуса — ударопрочный пластик и алюминиевый профиль.\n\n2. Вычислительный модуль: основной контроллер Raspberry Pi 5 (8GB RAM) для высокоуровневых задач компьютерного зрения и навигации, дополнительный микроконтроллер Arduino Due для низкоуровневого управления моторами и датчиками.\n\n3. Система технического зрения: камера глубины Intel RealSense D435i для RGB-изображения и карты глубины, дополнительная камера высокого разрешения Arducam 16MP для распознавания QR-кодов на пробирках. Для работы в условиях недостаточного освещения установлена программируемая LED-подсветка.\n\n4. Навигационные датчики: лидар RPLidar A1 с радиусом действия 12 метров для построения карт помещений, 4 ультразвуковых датчика HC-SR04 для обнаружения препятствий на близком расстоянии, 2 оптических энкодера на колесах для точного определения пройденного пути, IMU-модуль MPU6050 для определения ориентации в пространстве.\n\n5. Грузовая платформа: съемный лоток на 24 пробирки стандартного диаметра с системой фиксации, герметичный контейнер для сыпучих реактивов объемом 1 литр, крепления для штативов и лабораторной посуды.\n\n6. Энергосистема: литий-ионный аккумулятор 12V 20Ah, обеспечивающий до 4 часов автономной работы, система автоматической подзарядки с контактной станцией.\n\nПрограммное обеспечение робота состоит из нескольких взаимосвязанных модулей:\n\nМодуль навигации реализует алгоритмы SLAM (Simultaneous Localization and Mapping) для построения карты лаборатории и определения местоположения робота. Используется комбинация данных с лидара и одометрии для точного позиционирования. Планировщик маршрутов на основе алгоритма A* строит оптимальный путь к целевой точке с учетом препятствий.\n\nМодуль компьютерного зрения использует нейросеть YOLOv8, дообученную на датасете из 5000 изображений лабораторной посуды. Сеть распознает 12 классов объектов: пробирки разных типов, колбы, чашки Петри, штативы, пипетки. Отдельный классификатор на основе Tesseract OCR считывает QR-коды и текстовые метки на пробирках для идентификации содержимого.\n\nМодуль взаимодействия с ЛИС реализует API через MQTT-протокол. Робот получает задания в формате JSON, например: \"доставить пробирку с ID 12345 из стеллажа А3 на стол оператора 2\". После выполнения отправляет подтверждение с фотоотчетом.\n\nИнтерфейс оператора представляет собой веб-приложение, разработанное на React, через которое можно отслеживать состояние робота, просматривать историю перемещений, давать ручные команды и настраивать параметры работы.\n\nЭтапы реализации проекта:\n\n1. Январь-февраль 2025: Разработка концепции, выбор компонентов, проектирование механики в SolidWorks. Создание первого прототипа шасси.\n\n2. Март-апрель 2025: Разработка электроники и системы управления. Интеграция датчиков, написание драйверов. Начало работы над навигационной системой.\n\n3. Май-июнь 2025: Разработка и обучение системы компьютерного зрения. Сбор датасета в химической лаборатории. Тестирование распознавания.\n\n4. Июль-август 2025: Интеграция всех модулей. Написание API для связи с ЛИС. Создание пользовательского интерфейса.\n\n5. Сентябрь-октябрь 2025: Комплексное тестирование в лабораторных условиях. Сбор статистики, выявление и устранение проблем.\n\n6. Ноябрь-декабрь 2025: Полевые испытания в химической лаборатории университета. Подготовка документации и статей.\n\nОжидаемые результаты проекта:\n\n- Снижение времени на транспортировку образцов на 40-60%\n- Уменьшение риска контакта лаборантов с опасными веществами\n- Повышение точности учета образцов за счет автоматической фиксации перемещений в ЛИС\n- Создание открытой платформы, которую можно адаптировать под различные типы лабораторий\n\nПроект уже привлек внимание трех профильных кафедр университета и двух индустриальных партнеров. В случае успешных испытаний планируется тиражирование решения в другие научные и медицинские учреждения города.', '[\"Разработка аппаратной платформы\", \"Создание системы компьютерного зрения\", \"Реализация алгоритмов навигации\", \"Интеграция с ЛИС\", \"Полевые испытания в лаборатории\"]', '[\"ROS2\", \"OpenCV\", \"YOLOv8\", \"SLAM\", \"Raspberry Pi 5\", \"Arduino\"]', '2025-01-15', NULL, 'active', 'Университетский грант', '350000.00', '[\"1\", \"2\", \"3\"]', 'Создан рабочий прототип. Система зрения распознает пробирки с точностью 95%. Проведены первые тесты в химической лаборатории.', 'obschee/assets/img/project/робот4.jpg', '[\"/uploads/projects/lab-assistant-1.jpg\", \"/uploads/projects/lab-assistant-2.jpg\", \"/uploads/projects/lab-assistant-3.jpg\"]', 'published', 1, '2025-01-10 06:00:00', '2026-02-16 17:43:40'),
(2, 'Интеллектуальный мусоросборщик для кампуса', 'smart-waste-collector', 'Автономный робот для сбора и сортировки мусора в парках и на территории кампуса. Использует нейросети для распознавания пластика, бумаги и стекла.', 'Проект \"Интеллектуальный мусоросборщик\" направлен на решение экологической проблемы загрязнения общественных пространств с помощью автономного роботизированного комплекса. Робот предназначен для регулярной уборки территории университетского кампуса, городских парков и студенческих городков с возможностью не только сбора, но и первичной сортировки отходов.\n\nКонцепция проекта родилась из наблюдений за работой дворников и волонтеров на субботниках. Значительная часть времени тратится на сбор мелкого мусора, а раздельный сбор затруднен из-за необходимости сортировки вручную. Автоматизация этого процесса позволит повысить эффективность уборки и увеличить долю отходов, отправляемых на переработку.\n\nТехнические характеристики и конструктивные особенности:\n\nПлатформа робота выполнена на шестиколесном шасси с независимой подвеской каждого колеса, что обеспечивает высокую проходимость на различных поверхностях: асфальт, брусчатка, газон, грунтовые дорожки. Колеса с грунтозацепами предотвращают пробуксовку на траве и песке. Габариты: 70x50x40 см, масса 25 кг.\n\nСистема сбора состоит из нескольких элементов:\n- Фронтальные вращающиеся щетки для сметания мусора к центральному транспортеру\n- Ленточный транспортер с регулируемой скоростью для подъема мусора в контейнер\n- Всасывающий механизм с циклонным фильтром для мелкого мусора (окурки, бумажки, пыль)\n- Два сменных контейнера: основной (60 л) для смешанного мусора и дополнительный (30 л) с разделителем на две секции для предварительной сортировки\n\nСистема компьютерного зрения построена на базе Jetson Nano с камерой высокого разрешения Sony IMX219. Нейросетевая модель MobileNetV3 была дообучена на собственном датасете, содержащем более 5000 изображений мусора различных категорий, снятых в разных погодных условиях и освещении. Модель классифицирует объекты на 5 классов:\n- Пластиковые бутылки и упаковка\n- Бумажные стаканчики и упаковка\n- Стеклянные бутылки и банки\n- Алюминиевые банки\n- Прочий мусор (несортируемый)\n\nТочность классификации в лабораторных условиях достигает 91%, в реальных условиях парка — 87%. Время обработки одного кадра составляет 80 мс, что позволяет анализировать объекты в движении.\n\nНавигационная система использует комбинацию GPS/ГЛОНАСС модуля для глобального позиционирования на открытой местности и системы технического зрения для локальной навигации и объезда препятствий. Для работы в зонах с плохим приемом спутниковых сигналов (под деревьями, у зданий) реализован алгоритм визуальной одометрии. Робот может двигаться по заданному маршруту, автоматически объезжая пешеходов, скамейки, деревья и другие препятствия.\n\nЭнергетическая система включает литий-железо-фосфатный аккумулятор 24V 30Ah, обеспечивающий до 5 часов непрерывной работы. Предусмотрена автоматическая парковка на зарядной станции при снижении заряда ниже 20%. В ночное время робот может работать в режиме зарядки и передачи собранных данных на сервер.\n\nПрограммное обеспечение разработано на Python с использованием ROS2 для распределения задач между вычислительными модулями. Веб-интерфейс для оператора позволяет:\n- Задавать зоны уборки на карте\n- Отслеживать текущее местоположение робота\n- Просматривать статистику собранного мусора в реальном времени\n- Получать уведомления о заполнении контейнеров\n- Управлять роботом в ручном режиме при необходимости\n- Просматривать архив фотоотчетов о собранных объектах\n\nПартнеры проекта — экологический факультет университета и городская служба благоустройства — предоставляют доступ к территориям для тестирования и помогают с валидацией результатов.\n\nЭтапы реализации:\n\n1. Февраль-март 2025: Разработка технического задания, проектирование механики, заказ компонентов.\n\n2. Апрель-май 2025: Сборка первого прототипа шасси, отработка системы сбора.\n\n3. Июнь-июль 2025: Сбор датасета и обучение нейросети. Разработка навигационной системы.\n\n4. Август-сентябрь 2025: Интеграция всех систем. Написание ПО и пользовательского интерфейса.\n\n5. Октябрь-ноябрь 2025: Испытания на территории кампуса. Сбор статистики, доработка.\n\n6. Декабрь 2025: Презентация проекта городской администрации. Подготовка к коммерциализации.\n\nОжидаемые экологические и экономические эффекты:\n\n- Сокращение времени на уборку территории кампуса на 50% (с 4 часов до 2 часов ежедневно)\n- Увеличение доли собираемого вторсырья на 30% за счет автоматической сортировки\n- Снижение нагрузки на городские свалки\n- Вовлечение студентов в экологические проекты через участие в испытаниях и доработке робота\n- Создание базы для образовательных курсов по робототехнике и экологии\n\nПроект уже вызвал интерес со стороны нескольких коммерческих компаний, занимающихся клининговыми услугами, и экологических организаций. Планируется подача заявки на грант Фонда содействия инновациям.', '[\"Сбор данных для обучения нейросети\", \"Разработка системы сортировки\", \"Создание навигационной системы\", \"Автономная работа и подзарядка\", \"Полевые испытания\"]', '[\"TensorFlow Lite\", \"MobileNet\", \"Python\", \"Jetson Nano\", \"GPS/RTK\"]', '2025-02-01', '2025-12-31', 'active', 'Экологический фонд', '500000.00', '[\"2\", \"3\", \"4\"]', 'Собран датасет из 3000 изображений мусора. Точность сортировки 87%. Проведены испытания в городском парке.', 'obschee/assets/img/project/робот6.jpg', '[\"/uploads/projects/waste-collector-1.jpg\", \"/uploads/projects/waste-collector-2.jpg\"]', 'published', 2, '2025-01-20 08:30:00', '2026-02-16 17:41:48'),
(3, 'Персональный складской робот для инвентаризации', 'warehouse-inventory-robot', 'Компактный робот для автоматизации учета товаров на небольших складах, в библиотеках и архивах. Использует RFID-метки и техническое зрение для поиска и идентификации объектов.', 'Проект \"Персональный складской робот для инвентаризации\" представляет собой компактное автономное решение для автоматизации учета товаров на небольших складах, в библиотеках, архивах, магазинах и аптеках. Основная задача робота — регулярное проведение инвентаризации, поиск конкретных предметов и контроль наличия товаров на стеллажах.\n\nИдея проекта возникла после анализа проблем небольших предприятий: полная ручная инвентаризация требует остановки работы и привлечения нескольких сотрудников на 1-2 дня, а текущий учет часто неточен из-за человеческого фактора. Автоматизация этого процесса позволит проводить учет чаще (еженедельно или даже ежедневно) без остановки работы и с минимальными затратами.\n\nКонструкция робота оптимизирована для работы в условиях узких проходов между стеллажами:\n\nШасси: вертикальная компоновка высотой 120 см, шириной 40 см, длиной 50 см. Такая форма позволяет роботу свободно перемещаться в проходах шириной от 60 см. Колесная база — четыре колеса с возможностью поворота на 90 градусов, что обеспечивает разворот на месте в ограниченном пространстве. Центр тяжести смещен вниз для устойчивости.\n\nМанипулятор: телескопическая штанга с камерой на конце, выдвигающаяся до высоты 200 см. Это позволяет осматривать верхние полки стеллажей без увеличения габаритов робота. Камера имеет автофокус и светодиодную подсветку для работы в затемненных архивных помещениях.\n\nСистема идентификации объектов:\n\nОсновной метод — работа с RFID-метками. Робот оснащен четырьмя RFID-антеннами, расположенными по периметру на разных высотах, что обеспечивает считывание меток со всех сторон и на разных уровнях стеллажей. Мощность считывателя регулируется для точного определения местоположения метки (ближняя, средняя, дальняя зона).\n\nДополнительный метод — компьютерное зрение для распознавания корешков книг, этикеток и штрихкодов. Нейросеть обучена распознавать надписи на русском и английском языках с помощью OCR. Это необходимо для работы с объектами, не оснащенными RFID-метками.\n\nНавигационная система:\n\nРобот строит карту помещения с помощью лидара и уточняет свое положение относительно стеллажей по специальным маркерам, размещенным в начале и конце каждого ряда. Это обеспечивает точность позиционирования до 1 см, что критически важно для корректной привязки считанных меток к конкретным полкам.\n\nАлгоритм инвентаризации:\n\n1. Робот получает задание на инвентаризацию определенной зоны\n2. Двигается вдоль стеллажа, останавливаясь напротив каждой секции\n3. Считывает RFID-метки на этой секции\n4. Камера на манипуляторе поднимается/опускается для фотографирования полок\n5. Фотографии обрабатываются для распознавания визуальных меток и сверки с RFID\n6. Данные сравниваются с базой данных, формируется отчет о расхождениях\n7. При обнаружении предмета не на своем месте робот делает отметку для сотрудника\n\nПрограммное обеспечение состоит из нескольких модулей:\n\nМодуль управления роботом на ROS2 отвечает за навигацию и выполнение команд движения. Модуль инвентаризации координирует процесс учета и взаимодействует с базой данных. Веб-интерфейс оператора позволяет:\n- Загружать план помещения и расположение стеллажей\n- Запускать полную или выборочную инвентаризацию\n- Искать конкретный предмет по названию или ID\n- Просматривать отчеты о расхождениях с фотографиями\n- Экспортировать данные в Excel или 1С\n- Получать уведомления о критических расхождениях\n\nПартнеры проекта:\n\nУниверситетская библиотека предоставляет помещение для тестирования и доступ к фонду. Архив города заинтересован в решении для оцифровки и учета исторических документов. Небольшой магазин хобби и творчества тестирует робота для учета товаров на полках.\n\nЭтапы разработки:\n\n1. Март-апрель 2025: Проектирование конструкции с учетом требований библиотеки. Выбор RFID-оборудования.\n\n2. Май-июнь 2025: Сборка прототипа шасси и манипулятора. Разработка системы считывания RFID.\n\n3. Июль-август 2025: Разработка навигационной системы с привязкой к стеллажам. Создание базы данных учета.\n\n4. Сентябрь-октябрь 2025: Интеграция всех систем. Разработка веб-интерфейса.\n\n5. Ноябрь-декабрь 2025: Тестирование в библиотеке. Проведение сравнительной инвентаризации (робот vs люди).\n\n6. Январь-февраль 2026: Доработка по результатам испытаний. Подготовка коммерческого предложения.\n\nОжидаемые результаты:\n\n- Сокращение времени полной инвентаризации библиотеки (15000 книг) с 40 человеко-часов до 14 часов работы робота\n- Выявление книг, стоящих не на своих местах, с точностью 95%\n- Снижение трудоемкости поиска конкретной книги до 2-3 минут\n- Создание цифровой карты расположения предметов с фотографиями полок\n- Возможность проведения инвентаризации без закрытия библиотеки для посетителей\n\nТехнико-экономические показатели:\n\nСтоимость прототипа — 400 000 рублей. При массовом производстве ожидается снижение цены до 250-300 тысяч рублей. Окупаемость для типовой библиотеки — 1.5-2 года за счет экономии труда сотрудников. Потенциальный рынок — библиотеки, архивы, небольшие склады, аптеки, магазины.', '[\"Разработка шасси и манипулятора\", \"Интеграция RFID-считывателя\", \"Создание ПО для инвентаризации\", \"Тестирование в библиотеке\", \"Разработка интерфейса оператора\"]', '[\"RFID\", \"OpenCV\", \"ROS2\", \"Qt\", \"Python\", \"STM32\"]', '2025-03-01', NULL, 'active', 'Библиотечный консорциум', '400000.00', '[\"1\", \"3\", \"5\"]', 'Прототип протестирован в университетской библиотеке. Инвентаризация 15000 книг за 14 часов. Точность 94%.', 'obschee/assets/img/project/робот2.jpg', '[\"/uploads/projects/warehouse-robot-1.jpg\", \"/uploads/projects/warehouse-robot-2.jpg\"]', 'published', 3, '2025-02-15 07:15:00', '2026-02-16 17:39:25'),
(4, 'Агробот: автоматизированная платформа для ухода за растениями', 'agrobot-plant-care', 'Роботизированная система для автоматического полива, мониторинга влажности почвы, освещенности и температуры растений в теплицах и жилых помещениях.', 'Проект \"Агробот: автоматизированная платформа для ухода за растениями\" представляет собой роботизированную систему, предназначенную для автоматического ухода за растениями в теплицах, оранжереях, зимних садах и даже в обычных квартирах с большим количеством комнатных растений. Проект находится на стыке робототехники, агротехнологий и интернета вещей.\n\nИдея проекта родилась из личного опыта участников команды: частые командировки и отпуска приводили к гибели комнатных растений из-за отсутствия полива. Существующие автоматические системы полива стационарны и не могут обслуживать растения, расположенные в разных частях помещения. Мобильный робот может решить эту проблему, перемещаясь между растениями и обслуживая каждое по индивидуальной программе.\n\nКонструкция робота:\n\nПлатформа: трехколесная схема с двумя ведущими колесами и одним поворотным для обеспечения маневренности в ограниченном пространстве. Диаметр платформы 35 см, высота 25 см. Корпус из влагозащищенного пластика с классом защиты IP54.\n\nСистема полива:\n- Резервуар для воды объемом 5 литров из пищевого пластика\n- Два перистальтических насоса для точного дозирования воды (один для обычного полива, второй для удобрений)\n- Выдвижная телескопическая штанга с насадкой для точечного полива (высота подъема до 80 см)\n- Система капельного полива для растений, требующих медленного увлажнения\n- Датчик уровня воды с оповещением о необходимости дозаправки\n\nСистема датчиков:\n- Датчик влажности почвы (робот подносит щуп к земле для измерения)\n- Датчик освещенности для оценки доступности света для каждого растения\n- Датчик температуры и влажности воздуха DHT22\n- Камера для визуального мониторинга состояния листьев (распознавание увядания, пожелтения, пятен)\n- Датчик расстояния для навигации и объезда препятствий\n\nНавигационная система:\n\nВ помещениях без специальной инфраструктуры робот использует визуальную одометрию и построение карты методом SLAM. Для точного позиционирования у каждого горшка размещается QR-код, по которому робот определяет, какое растение перед ним. Альтернативный вариант — использование UWB-меток для высокоточной навигации в теплицах.\n\nИнтеллектуальная система ухода:\n\nДля каждого растения в базе данных хранится индивидуальный профиль:\n- Оптимальная влажность почвы (в процентах)\n- Частота полива\n- Объем воды на один полив\n- Требования к освещенности\n- История поливов и измерений\n\nНа основе показаний датчиков и прогноза погоды (если робот имеет доступ к интернету) система корректирует график полива. Например, перед жарким днем может увеличить объем воды или полить раньше обычного.\n\nАлгоритм работы:\n\n1. Робот перемещается по расписанию или по команде пользователя\n2. Подъезжает к растению, идентифицирует его по QR-коду\n3. Измеряет влажность почвы датчиком\n4. Если влажность ниже пороговой, производит полив рассчитанным объемом воды\n5. Фотографирует растение и сохраняет снимок для истории\n6. Переходит к следующему растению или возвращается на базу\n7. При низком уровне воды или заряда автоматически паркуется на зарядной станции и отправляет уведомление\n\nПользовательский интерфейс:\n\nМобильное приложение для iOS и Android позволяет:\n- Добавлять новые растения и задавать параметры ухода\n- Просматривать историю поливов и фотографии растений\n- Получать уведомления о критических ситуациях (низкая влажность, болезни растений)\n- Управлять роботом вручную (подъехать, полить конкретное растение)\n- Просматривать статистику по расходу воды и состоянию растений\n\nВеб-версия интерфейса предоставляет аналогичный функционал и доступна с компьютера.\n\nПартнеры проекта:\n\nБотанический сад университета предоставляет теплицы для тестирования и консультации агрономов. Студенческое объединение экологов помогает с валидацией результатов. Несколько частных лиц уже выразили желание протестировать робота в домашних условиях.\n\nЭтапы реализации:\n\n1. Февраль-март 2025: Проектирование платформы и системы полива. Выбор компонентов.\n\n2. Апрель-май 2025: Сборка первого прототипа. Отработка механизма полива и дозирования воды.\n\n3. Июнь-июль 2025: Разработка навигационной системы и распознавания QR-кодов.\n\n4. Август-сентябрь 2025: Создание базы данных растений и алгоритмов принятия решений.\n\n5. Октябрь-ноябрь 2025: Разработка мобильного и веб-приложений.\n\n6. Декабрь 2025: Комплексное тестирование в теплице и в квартирах. Сбор отзывов.\n\n7. Январь-февраль 2026: Доработка по результатам тестирования. Подготовка к производству малой серии.\n\nРезультаты тестирования прототипа:\n\nВ марте-апреле 2025 года проведено двухнедельное тестирование в квартире одного из разработчиков. Под наблюдением находились 12 растений различных видов: суккуленты, фикусы, орхидеи, папоротники, томаты на балконе. Результаты:\n- Выживаемость растений — 100%\n- Точность измерения влажности почвы — 93%\n- Успешность полива (попадание воды в горшок) — 98% после калибровки\n- Среднее время на обслуживание одного растения — 2 минуты\n- Расход воды — на 15% меньше ручного полива за счет точного дозирования\n\nПроблемы, выявленные в ходе тестирования:\n- Кот проявил агрессию к роботу, пришлось добавить алгоритм избегания животных\n- Некоторые растения стояли слишком близко друг к другу, робот не мог подъехать\n- Влажность почвы суккулентов измерялась некорректно из-за особенностей грунта\n\nВсе проблемы были проанализированы и учтены в следующей версии прототипа.\n\nПерспективы коммерциализации:\n\nЦелевая аудитория проекта:\n- Владельцы частных домов и квартир с большим количеством растений\n- Ботанические сады и оранжереи\n- Тепличные хозяйства\n- Учебные заведения (кабинеты биологии)\n- Офисы с фитодизайном\n\nПотенциальная стоимость готового устройства — 40-60 тысяч рублей в зависимости от комплектации. Рынок в России оценивается в 10-15 тысяч потенциальных покупателей в ближайшие 3 года.', '[\"Создание мобильной платформы\", \"Интеграция датчиков\", \"Разработка системы автополива\", \"Создание веб-интерфейса\", \"Домашнее тестирование\"]', '[\"Arduino\", \"ESP32\", \"MQTT\", \"React\", \"Node.js\", \"Датчики влажности\"]', '2025-02-15', '2025-08-30', 'active', 'Стартап-акселератор', '250000.00', '[\"4\", \"5\", \"2\"]', 'Создан прототип. Успешное двухнедельное тестирование в квартире. Все растения выжили.', 'obschee/assets/img/project/робот5.jpg', '[\"/uploads/projects/agrobot-1.jpg\", \"/uploads/projects/agrobot-2.jpg\", \"/uploads/projects/agrobot-3.jpg\"]', 'published', 4, '2025-02-01 11:45:00', '2026-02-16 17:41:43'),
(5, 'Образовательный робототехнический конструктор для вузов', 'educational-robotics-kit', 'Разработка открытого образовательного набора для обучения студентов основам робототехники, компьютерного зрения и программирования на базе ROS2.', 'Проект \"Образовательный робототехнический конструктор для вузов\" направлен на создание открытого учебно-методического комплекса для практического обучения студентов основам робототехники, компьютерного зрения, навигации и программирования встраиваемых систем на базе современных технологий ROS2.\n\nАктуальность проекта обусловлена растущим спросом на специалистов в области робототехники и недостатком практических учебных материалов, доступных для вузов. Существующие образовательные конструкторы часто либо слишком просты (уровень школы), либо слишком дороги и закрыты (промышленные образцы). Наш проект предлагает золотую середину: доступный по цене, но достаточно сложный и профессиональный набор, позволяющий студентам освоить реальные технологии, используемые в индустрии.\n\nКонцепция и философия проекта:\n\nМы не просто создаем набор деталей, а разрабатываем целостную образовательную экосистему, включающую:\n- Аппаратную платформу с открытой архитектурой\n- Программное обеспечение с открытым исходным кодом\n- Методические материалы для проведения лабораторных работ\n- Симуляторы для отработки алгоритмов без железа\n- Сообщество преподавателей и студентов для обмена опытом\n- Систему повышения квалификации для преподавателей\n\nСостав образовательного комплекса:\n\nАппаратная часть:\n- Базовое шасси: колесная платформа из алюминиевого профиля с возможностью установки различных типов колес (обычные, всенаправленные, гусеницы)\n- Контроллеры: основной модуль на базе Raspberry Pi 4/5 для высокоуровневых задач и дополнительный микроконтроллер ESP32 или STM32 для низкоуровневого управления\n- Набор датчиков: ультразвуковые дальномеры (2 шт.), датчики линии (4 шт.), камера (8 МП), энкодеры на колесах (2 шт.), IMU-модуль, лидар RPLidar A1 (опционально)\n- Исполнительные устройства: моторы с редукторами (2-4 шт.), сервоприводы (2 шт.), светодиодная индикация\n- Энергосистема: аккумуляторная батарея с контроллером заряда и защитой\n- Конструктор для сборки манипулятора: набор сервоприводов и креплений для создания простого захвата\n\nПрограммная часть:\n- Базовая прошивка для микроконтроллера с реализацией PID-регуляторов для управления моторами\n- ROS2 пакеты для Raspberry Pi с готовыми нодами для работы с датчиками\n- Примеры реализации основных алгоритмов (следование по линии, объезд препятствий, SLAM, навигация)\n- Docker-образы с предустановленным ROS2 и зависимостями для быстрого старта\n- Симулятор Gazebo с моделью робота для отработки алгоритмов без железа\n\nМетодические материалы:\n\nКурс разбит на модули с возрастающей сложностью:\n\nМодуль 1. Введение в робототехнику (4 лабораторные работы)\n- Знакомство с платформой, установка ПО\n- Основы работы с GPIO, мигание светодиодом\n- Подключение и опрос датчиков\n- Управление моторами, базовое движение\n\nМодуль 2. Основы ROS2 (6 лабораторных работ)\n- Установка ROS2, основные концепции (ноды, топики, сервисы)\n- Создание простых издателей и подписчиков\n- Работа с параметрами и launch-файлами\n- Запись и воспроизведение rosbag\n- Моделирование робота в URDF\n\nМодуль 3. Навигация и управление движением (5 лабораторных работ)\n- Одометрия и энкодеры\n- PID-регуляторы для точного движения\n- Планирование траекторий\n- Алгоритмы следования по линии\n- Объезд препятствий\n\nМодуль 4. Компьютерное зрение (5 лабораторных работ)\n- Захват изображения с камеры в ROS2\n- Обработка изображений с OpenCV\n- Распознавание объектов с помощью нейросетей\n- Интеграция TensorFlow Lite на Raspberry Pi\n- Следование за объектом\n\nМодуль 5. Продвинутая навигация (4 лабораторные работы)\n- SLAM: построение карты помещения\n- Локализация на карте (amcl)\n- Планирование маршрута (Nav2)\n- Автономное движение по точкам\n\nМодуль 6. Проектная работа (индивидуально или в группах)\n- Разработка собственного проекта на базе платформы\n- Защита проекта перед комиссией\n\nПилотное внедрение:\n\nПроект будет апробирован на трех курсах:\n- Курс \"Введение в робототехнику\" для студентов 2 курса (весна 2026)\n- Курс \"Программирование роботов\" для студентов 3 курса (осень 2026)\n- Курс повышения квалификации для преподавателей информатики (лето 2026)\n\nВ пилотном проекте примут участие 30 студентов и 5 преподавателей. По результатам будут собраны отзывы и внесены исправления в методические материалы.\n\nПартнеры проекта:\n\nКафедра робототехники университета выступает основным партнером и предоставляет преподавателей для разработки методических материалов. Институт повышения квалификации учителей заинтересован в курсе для школьных преподавателей. Технопарк \"Кванториум\" планирует использовать конструктор для занятий со школьниками.\n\nТехнико-экономические показатели:\n\nСтоимость одного комплекта в базовой комплектации (без лидара, с Raspberry Pi 4) — 25 000 рублей. Стоимость расширенного комплекта (с лидаром и Raspberry Pi 5) — 40 000 рублей. Для университетов предусмотрена скидка при заказе от 10 комплектов.\n\nПлан производства:\n\n- Апрель-июнь 2025: Разработка конструкторской документации, выбор поставщиков\n- Июль-сентябрь 2025: Сборка 10 пилотных комплектов\n- Октябрь-декабрь 2025: Апробация на курсах, сбор обратной связи\n- Январь-март 2026: Доработка по результатам пилота\n- Апрель 2026: Запуск малой серии (50 комплектов)\n\nОжидаемые результаты:\n\n- Повышение качества подготовки студентов в области робототехники\n- Увеличение числа выпускников, трудоустраивающихся по специальности\n- Создание открытого сообщества разработчиков образовательных решений\n- Вовлечение школьников в робототехнику через профориентационные мероприятия\n- Публикация учебного пособия с грифом УМО\n\nПроект поддержан учебно-методическим советом университета и включен в программу развития цифровых компетенций студентов.', '[\"Разработка аппаратной платформы\", \"Создание учебных модулей\", \"Написание методичек\", \"Пилотное внедрение\", \"Организация хакатонов\"]', '[\"ROS2\", \"Gazebo\", \"Raspberry Pi\", \"Python\", \"C++\", \"OpenCV\"]', '2025-04-01', '2025-12-31', 'planned', 'Образовательный грант', '600000.00', '[\"1\", \"2\", \"3\", \"4\", \"5\"]', 'Планируется создание 10 учебных комплектов и апробация на 3 курсах.', 'obschee/assets/img/project/робот9.jpg', '[\"/uploads/projects/edu-kit-1.jpg\"]', 'published', 5, '2025-03-10 09:00:00', '2026-02-16 17:45:19');

